import{j as l,b as a,c as i,aa as t}from"./chunks/framework.Bxf40uRC.js";const u=JSON.parse('{"title":"HTTP","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/HTTP.md","filePath":"计算机网络/HTTP.md","lastUpdated":null}'),o={name:"计算机网络/HTTP.md"},e=t('<h1 id="http" tabindex="-1">HTTP <a class="header-anchor" href="#http" aria-label="Permalink to &quot;HTTP&quot;">​</a></h1><h2 id="不同层的数据叫做什么名字" tabindex="-1">不同层的数据叫做什么名字 <a class="header-anchor" href="#不同层的数据叫做什么名字" aria-label="Permalink to &quot;不同层的数据叫做什么名字&quot;">​</a></h2><p>应用层：应用数据</p><p>传输层：数据段</p><p>网络层：数据包</p><p>数据链路层：数据帧</p><p>物理层：比特流</p><h2 id="https" tabindex="-1">HTTPS <a class="header-anchor" href="#https" aria-label="Permalink to &quot;HTTPS&quot;">​</a></h2><ol><li>防止监听，采用对称密钥进行加密</li><li>防止篡改，采用数字签名进行认证</li><li>防止冒充，采用CA作为认证</li><li>客户端要和服务端进行连接时，首先会通过非对称密钥协商一个对称加密密钥，后续通过对称密钥进行通信;</li><li>如果这个过程中因为自己的原因，点进入了一个非合法的网站，那么就有可能存在冒充的风险;</li></ol><h2 id="http-1-1-相比于http-1-0-提高了什么性能" tabindex="-1">HTTP/1.1 相比于HTTP/1.0 提高了什么性能? <a class="header-anchor" href="#http-1-1-相比于http-1-0-提高了什么性能" aria-label="Permalink to &quot;HTTP/1.1 相比于HTTP/1.0 提高了什么性能?&quot;">​</a></h2><h3 id="优点" tabindex="-1">优点: <a class="header-anchor" href="#优点" aria-label="Permalink to &quot;优点:&quot;">​</a></h3><ol><li>使用长连接改善了1.0短链接造成的额外开销</li><li>支持管道网络传输，只要第一个请求发出去了，不必等其回来，就可以发出第二个请求出去</li></ol><h3 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to &quot;缺点&quot;">​</a></h3><ol><li>请求/响应头部未经压缩就发送，首部信息越多，延迟越大</li><li>服务器是按请求的顺序响应的，如果服务器响应慢，就会导致客户端一直请求不到数据，也就是队头阻塞；</li><li>没有请求优先级控制</li><li>请求只能通过客户端开始，服务器端只能被动响应</li></ol><h2 id="http2做了什么优化-相比于1-1" tabindex="-1">HTTP2做了什么优化？(相比于1.1) <a class="header-anchor" href="#http2做了什么优化-相比于1-1" aria-label="Permalink to &quot;HTTP2做了什么优化？(相比于1.1)&quot;">​</a></h2><h3 id="优点-1" tabindex="-1">优点 <a class="header-anchor" href="#优点-1" aria-label="Permalink to &quot;优点&quot;">​</a></h3><ol><li>头部压缩 <ul><li>HPACK算法，如果同时发送多个请求，头部相似，协议会帮你消除相似的部分</li><li>在客户端和服务器同时维护一张头信息表，所有字段都会存入这个表，生成一个索引号，以后就不发送同样字段了，只发送索引号，这样就<strong>提高速度</strong>了</li></ul></li><li>二进制格式 <ul><li>不采用1.1中的纯文本形式报文，全面采用了二进制格式，分为<strong>头部信息帧</strong>和<strong>数据帧</strong></li></ul></li><li>并发传输 <ul><li>引入了Stream概念，一个TCP连接上可以包含多个Stream，Message包含一条或者多个Frame，每一个响应对应的Stream ID是独一无二的，客户端会根据相同的Stream ID组装消息</li></ul></li><li>服务器主动推送资源 <ul><li>客户端和服务器<strong>双方都可以建立 Stream</strong>， Stream ID 也是有区别的，客户端建立的 Stream 必须是奇数号，而服务器建立的 Stream 必须是偶数号。</li><li>在 HTTP/2 中，客户端在访问 HTML 时，服务器可以直接主动推送 CSS 文件，减少了消息传递的次数。</li></ul></li></ol><h3 id="缺点-1" tabindex="-1">缺点 <a class="header-anchor" href="#缺点-1" aria-label="Permalink to &quot;缺点&quot;">​</a></h3><ol><li><p><strong>HTTP/2 是基于 TCP 协议来传输数据的，TCP 是字节流协议，TCP 层必须保证收到的字节数据是完整且连续的，这样内核才会将缓冲区里的数据返回给 HTTP 应用，那么当「前 1 个字节数据」没有到达时，后收到的字节数据只能存放在内核缓冲区里，只有等到这 1 个字节数据到达时，HTTP/2 应用层才能从内核中拿到数据，这就是 HTTP/2 队头阻塞问题。</strong></p><p><img src="https://cdn.xiaolincoding.com/gh/xiaolincoder/ImageHost4@main/%E7%BD%91%E7%BB%9C/http3/tcp%E9%98%9F%E5%A4%B4%E9%98%BB%E5%A1%9E.gif" alt="img"></p></li></ol><h2 id="http3-做了哪些优化" tabindex="-1">HTTP3 做了哪些优化？ <a class="header-anchor" href="#http3-做了哪些优化" aria-label="Permalink to &quot;HTTP3 做了哪些优化？&quot;">​</a></h2><h3 id="优点-2" tabindex="-1">优点 <a class="header-anchor" href="#优点-2" aria-label="Permalink to &quot;优点&quot;">​</a></h3><ol><li>HTTP/2 队头阻塞的问题是因为 TCP，所以 <strong>HTTP/3 把 HTTP 下层的 TCP 协议改成了 UDP！</strong></li><li>UDP 发送是不管顺序，也不管丢包的，所以不会出现像 HTTP/2 队头阻塞的问题。大家都知道 UDP 是不可靠传输的，但基于 UDP 的 <strong>QUIC 协议</strong> 可以实现类似 TCP 的可靠性传输。QUIC 有以下 3 个特点。 <ul><li>无队头阻塞</li><li>更快的连接建立 <ul><li>对于 HTTP/1 和 HTTP/2 协议，TCP 和 TLS 是分层的，分别属于内核实现的传输层、openssl 库实现的表示层，因此它们难以合并在一起，需要分批次来握手，先 TCP 握手，再 TLS 握手。 <img src="https://cdn.xiaolincoding.com/gh/xiaolincoder/ImageHost/%E8%AE%A1%E7%AE%97%E6%9C%BA%E7%BD%91%E7%BB%9C/HTTP/28-HTTP3%E4%BA%A4%E4%BA%92%E6%AC%A1%E6%95%B0.png" alt="TCP HTTPS（TLS/1.3） 和 QUIC HTTPS "></li></ul></li><li>连接迁移 <ul><li>QUIC 是一个在 UDP 之上的<strong>伪</strong> TCP + TLS + HTTP/2 的多路复用的协议。</li><li>而 QUIC 协议没有用四元组的方式来“绑定”连接，而是通过<strong>连接 ID</strong> 来标记通信的两个端点，客户端和服务器可以各自选择一组 ID 来标记自己，因此即使移动设备的网络变化后，导致 IP 地址变化了，只要仍保有上下文信息（比如连接 ID、TLS 密钥等），就可以“无缝”地复用原连接，消除重连的成本，没有丝毫卡顿感，达到了<strong>连接迁移</strong>的功能。</li></ul></li></ul></li></ol><h3 id="缺点-2" tabindex="-1">缺点 <a class="header-anchor" href="#缺点-2" aria-label="Permalink to &quot;缺点&quot;">​</a></h3><ol><li>QUIC 是新协议，对于很多网络设备，根本不知道什么是 QUIC，只会当做 UDP，这样会出现新的问题，因为有的网络设备是会丢掉 UDP 包的，而 QUIC 是基于 UDP 实现的，那么如果网络设备无法识别这个是 QUIC 包，那么就会当作 UDP包，然后被丢弃。</li><li>HTTP/3 现在普及的进度非常的缓慢，不知道未来 UDP 是否能够逆袭 TCP。</li></ol><h2 id="键入网址到网页显示-期间发生了什么" tabindex="-1">键入网址到网页显示，期间发生了什么？ <a class="header-anchor" href="#键入网址到网页显示-期间发生了什么" aria-label="Permalink to &quot;键入网址到网页显示，期间发生了什么？&quot;">​</a></h2><ul><li><p>浏览器的第一步工作就是对URL协议进行解析，生成请求信息；</p></li><li><p>查询服务器域名对应的IP地址；具体过程就是先请求根域名，然后顶级域名，到权威域名服务器；</p></li><li><p>进行TCP连接，三次握手等，生成<strong>数据段</strong>；</p></li><li><p>TCP连接生成的数据段需要IP模块将其发送出去，通过IP进行远程定位，生成IP<strong>数据包</strong>；</p></li><li><p>网络中传输，到了数据链路层部分，此时需要mac地址定位具体的主机在哪，生成<strong>数据帧</strong>，MAC地址通过ARP地址解析协议获取，其中涉及到<strong>ARP缓存</strong>；</p></li><li><p>然后数据从网卡出去，交换机送出即可；</p><ul><li>交换机是二层网络设备，端口不具有MAC地址，但是存在MAC地址表，包含设备MAC地址和对应的端口；</li><li>如果不存在对应的映射，就会广播到除了源端口之外的所有端口；</li></ul></li><li><p>网络包经过交换机，到达路由器，然后路由器根据ip地址和网关的映射，转发到下一个路由器；</p><ul><li>通过ip地址和子网掩码进行异或，然后和网关地址对比，然后决定路由地址；</li></ul></li><li><p>到达对方之后，反向去除头部获取信息，最终送达服务端的某个服务即可；</p></li></ul><img src="https://s2.loli.net/2024/05/10/zrwiV2lMpWmeBZv.jpg" alt="MAC 层报文" style="zoom:33%;">',27),r=[e];function n(T,s,h,P,p,d){return a(),i("div",null,r)}const g=l(o,[["render",n]]);export{u as __pageData,g as default};
